const form = $('Input Gaya Bahasa').first().json || {};
const taxonomy = $input.first().json || {};
const gaya = form['Gaya Bahasa'];
const botId = String(form['Bot ID'] || '').trim();
const intentFilterRaw = String(form['Intent Key Filter (opsional)'] || '').trim();

if (!botId) {
  throw new Error('Bot ID wajib diisi untuk generator taxonomy-driven');
}

const strategyMap = {
  engagement: ['warm_welcome','quick_assist','question_led','reassuring'],
  discovery: ['overview_first','benefit_first','clarifying_question','process_explainer'],
  evaluation: ['value_reframe','risk_reversal','social_proof','comparison_reframe','objection_handling'],
  conversion: ['soft_cta','next_step_guidance','friction_reduction','confirmation_reassurance'],
  retention: ['empathy_first','apology_solution','process_clarity','reassurance_followup']
};

const parseStrategyPool = (value, category) => {
  if (Array.isArray(value)) {
    const arr = value.map(v => String(v || '').trim()).filter(Boolean);
    return arr.length ? arr : (strategyMap[category] || ['general_response']);
  }
  if (typeof value === 'string') {
    const s = value.trim();
    if (!s) return strategyMap[category] || ['general_response'];
    try {
      const parsed = JSON.parse(s);
      if (Array.isArray(parsed)) {
        const arr = parsed.map(v => String(v || '').trim()).filter(Boolean);
        return arr.length ? arr : (strategyMap[category] || ['general_response']);
      }
    } catch {}
    return s.split(',').map(v => v.trim()).filter(Boolean);
  }
  return strategyMap[category] || ['general_response'];
};

const filterKeys = new Set(
  intentFilterRaw
    ? intentFilterRaw.split(',').map(v => v.trim()).filter(Boolean)
    : []
);

let intents = Array.isArray(taxonomy.intents) ? taxonomy.intents : [];
if (!intents.length && Array.isArray(taxonomy.subcategories)) {
  intents = taxonomy.subcategories.map((sub) => ({
    key: sub.key,
    category_key: sub.category_key,
    label: sub.label,
    description: sub.description,
    reply_mode: sub.reply_mode,
    greeting_policy: sub.greeting_policy,
    default_template_count: sub.default_template_count,
    strategy_pool: sub.strategy_pool,
    is_active: sub.effective_is_active ?? sub.is_active
  }));
}

if (taxonomy.migration_required) {
  throw new Error('Taxonomy belum tersedia. Jalankan migration: ' + taxonomy.migration_required);
}

intents = intents.filter((i) => i && i.key && i.is_active !== false);
if (filterKeys.size > 0) {
  intents = intents.filter((i) => filterKeys.has(String(i.key)));
}

if (!intents.length) {
  throw new Error(filterKeys.size > 0
    ? 'Tidak ada intent aktif yang cocok dengan filter: ' + Array.from(filterKeys).join(', ')
    : 'Tidak ada intent aktif pada taxonomy bot ini');
}

const queue = intents.map((i) => {
  const intent = String(i.key);
  const category = String(i.category_key || intent.split('.')[0] || 'general');
  const targetCount = Math.max(1, Number(i.default_template_count || 3));
  const strategyPool = parseStrategyPool(i.strategy_pool, category);
  return {
    category,
    intent,
    label: String(i.label || '').trim() || intent,
    desc: String(i.description || '').trim() || ('Template untuk intent ' + intent),
    count: targetCount,
    target_count: targetCount,
    generation_count: targetCount + 2,
    reply_mode: String(i.reply_mode || 'continuation'),
    greeting_policy: String(i.greeting_policy || 'forbidden'),
    strategy_pool: strategyPool,
    gaya,
    botId,
    taxonomy_source: 'db'
  };
});

queue.sort((a, b) => a.category.localeCompare(b.category) || a.intent.localeCompare(b.intent));
return queue.map((q) => ({ json: q }));

const item = $input.first().json;
const targetCount = item.target_count || item.count || 3;
const generationCount = item.generation_count || (targetCount + 2);
const strategyPool = Array.isArray(item.strategy_pool) ? item.strategy_pool : [];
const replyMode = item.reply_mode || 'continuation';
const greetingPolicy = item.greeting_policy || 'forbidden';
const intentLabel = item.label || item.intent;

const modeRules = [];
if (replyMode === 'continuation') {
  modeRules.push('Balasan ini HARUS terasa sebagai lanjutan percakapan, bukan pembuka chat baru.');
  modeRules.push('JANGAN mulai dengan sapaan pembuka seperti Halo/Hai/Hei/Selamat pagi/siang/sore/malam.');
  modeRules.push('JANGAN gunakan pembuka generik seperti Terima kasih sudah menghubungi atau Ada yang bisa kami bantu.');
  modeRules.push('Mulai langsung dengan acknowledgement atau jawaban, contoh: Paham Kak..., Untuk..., Terkait..., Maaf ya Kak..., Siap Kak....');
}
if (replyMode === 'mixed') {
  modeRules.push('Boleh pakai sapaan singkat bila natural, tapi jangan selalu terasa seperti membuka chat baru.');
}
if (replyMode === 'opening') {
  modeRules.push('Sapaan pembuka diperbolehkan dan biasanya diperlukan.');
}
if (greetingPolicy === 'forbidden') {
  modeRules.push('Greeting policy = forbidden: hindari sapaan pembuka eksplisit kecuali sangat perlu untuk konteks natural.');
}
if (greetingPolicy === 'required') {
  modeRules.push('Greeting policy = required: sertakan sapaan pembuka yang natural.');
}

const examples = [];
if (replyMode === 'continuation') {
  examples.push('CONTOH BENAR continuation: Paham Kak, untuk reschedule sesi {nama_jasa} bisa lewat {link_daftar} ya. Kalau mau, kami bantu cek slot yang tersedia juga.');
  examples.push('CONTOH SALAH continuation: Hai {nama_pelanggan}! Ada yang bisa kami bantu hari ini?');
}
if (replyMode === 'opening') {
  examples.push('CONTOH BENAR opening: Halo Kak {nama_pelanggan}! Terima kasih sudah menghubungi {nama_bisnis}. Ada yang bisa kami bantu hari ini?');
}

const lines = [
  'Kamu adalah Master Copywriter yang menulis TEMPLATE PESAN untuk BOT Customer Service (CS/Admin), bukan pelanggan.',
  '',
  'SUMBER TAXONOMY: intent aktif dari database bot (taxonomy-driven generator).',
  '',
  'TUJUAN:',
  '- Buat ' + generationCount + ' draft template untuk intent ' + item.intent,
  '- Sistem akan memvalidasi & memilih ' + targetCount + ' template terbaik',
  '',
  'KONTEKS INTENT:',
  '- category: ' + item.category,
  '- intent key: ' + item.intent,
  '- intent label: ' + intentLabel,
  '- deskripsi intent: ' + item.desc,
  '- gaya bahasa: ' + item.gaya,
  '- reply_mode: ' + replyMode,
  '- greeting_policy: ' + greetingPolicy,
  '',
  'ATURAN WAJIB:',
  '1. Sudut pandang HARUS dari CS/Admin yang membalas pelanggan.',
  '2. DILARANG mengarang nama bisnis/produk/harga spesifik/alamat spesifik/nomor kontak spesifik.',
  '3. Placeholder yang boleh dipakai: {nama_pelanggan}, {nama_bisnis}, {nama_jasa}, {nama_paket}, {harga}, {link_daftar}, {jam_operasional}, {lokasi}, {kontak_admin}',
  '4. Jika perlu info KB gunakan marker [RAG: ...].',
  '5. Variasi harus berbeda strategi/angle/urutan, bukan cuma sinonim.',
  '6. Panjang ideal 2-5 kalimat.',
  '7. Jangan gunakan markdown code fence.',
  '',
  'ATURAN MODE BALASAN:',
  ...modeRules,
  '',
  'CONTOH:',
  ...examples,
  '',
  'STRATEGY TAG (usahakan unik dalam satu batch): ' + (strategyPool.join(', ') || 'general_response'),
  '',
  'OUTPUT VALID JSON ARRAY SAJA:',
  '[',
  '  {',
  '    "name": "Nama strategi singkat",',
  '    "strategy_tag": "tag_strategi",',
  '    "content": "Isi pesan bot",',
  '    "category": "' + item.category + '",',
  '    "sub_category": "' + item.intent + '",',
  '    "requires_rag": false',
  '  }',
  ']'
];

return [{
  json: {
    intent: item.intent,
    category: item.category,
    label: intentLabel,
    targetCount,
    generationCount,
    strategyPool,
    replyMode,
    greetingPolicy,
    taxonomySource: item.taxonomy_source || 'db',
    systemPrompt: lines.join('\n'),
    userPrompt: 'Buat ' + generationCount + ' draft template untuk intent ' + item.intent + ' (' + intentLabel + '). Patuhi reply_mode=' + replyMode + ' dan greeting_policy=' + greetingPolicy + '. Output VALID JSON array saja, tanpa pembuka.'
  }
}];

const src = $input.first().json || {};
const promptData = $('Build Agnostic Prompt').first().json;
const raw = String(src.text || (src.response && src.response.text) || src.output || '');
let cleaned = raw.trim();
const bt = String.fromCharCode(96);
cleaned = cleaned.split(bt + bt + bt + 'json').join('');
cleaned = cleaned.split(bt + bt + bt).join('');

const firstBracket = cleaned.indexOf('[');
const lastBracket = cleaned.lastIndexOf(']');
if (firstBracket !== -1 && lastBracket !== -1 && lastBracket > firstBracket) {
  cleaned = cleaned.slice(firstBracket, lastBracket + 1);
}

const normalizeBool = (v) => {
  if (typeof v === 'boolean') return v;
  if (typeof v === 'string') return ['true', 'yes', '1'].includes(v.trim().toLowerCase());
  return false;
};

let templates = [];
let parseOk = false;
let parseError = null;
try {
  const parsed = JSON.parse(cleaned);
  if (!Array.isArray(parsed)) throw new Error('Output is not a JSON array');
  templates = parsed.map((t, idx) => ({
    name: String((t && (t.name || t.title || t.strategy)) || ('Template ' + (idx + 1))).trim(),
    strategy_tag: String((t && (t.strategy_tag || t.strategy)) || '').trim(),
    content: String((t && (t.content || t.template || t.text || t.message)) || '').trim(),
    category: promptData.category,
    sub_category: promptData.intent,
    requires_rag: normalizeBool(t && t.requires_rag) || /\[RAG:/i.test(String((t && (t.content || t.template || t.text || t.message)) || ''))
  }));
  parseOk = true;
} catch (e) {
  parseError = e.message;
}

return [{
  json: {
    intent: promptData.intent,
    category: promptData.category,
    label: promptData.label || promptData.intent,
    targetCount: promptData.targetCount,
    generationCount: promptData.generationCount,
    strategyPool: promptData.strategyPool || [],
    replyMode: promptData.replyMode || 'continuation',
    greetingPolicy: promptData.greetingPolicy || 'forbidden',
    taxonomySource: promptData.taxonomySource || 'db',
    raw_output: raw,
    parse_ok: parseOk,
    parse_error: parseError,
    parsed_count: templates.length,
    templates
  }
}];

const input = $input.first().json || {};
const intent = input.intent;
const category = input.category;
const label = input.label || input.intent || input.category;
const taxonomySource = input.taxonomySource || 'db';
const targetCount = input.targetCount || 3;
const replyMode = input.replyMode || 'continuation';
const greetingPolicy = input.greetingPolicy || 'forbidden';
const strategyPool = Array.isArray(input.strategyPool) ? input.strategyPool : [];
const sourceTemplates = Array.isArray(input.templates) ? input.templates : [];

const allowedPlaceholders = new Set(['nama_pelanggan','nama_bisnis','nama_jasa','nama_paket','harga','link_daftar','jam_operasional','lokasi','kontak_admin']);
const openerRegex = /^\s*(halo|hai|hei|hello|selamat\s+(pagi|siang|sore|malam))\b/i;
const openingPhrases = [/terima kasih sudah menghubungi/i, /ada yang bisa kami bantu/i];
const continuationSignals = [/^\s*(paham|baik|siap|maaf|untuk|terkait)\b/i, /kami\s+(cek|bantu|proses)/i, /untuk\s+/i, /terkait\s+/i];

const normalizeText = (s) => String(s || '')
  .toLowerCase()
  .replace(/\[rag:[^\]]+\]/gi, '[rag]')
  .replace(/\{[^}]+\}/g, '{var}')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const extractPlaceholders = (s) => {
  const out = [];
  const re = /\{([^{}]+)\}/g;
  let m;
  while ((m = re.exec(String(s || ''))) !== null) out.push(m[1].trim());
  return out;
};

const looksCustomerPerspective = (text) => {
  const t = String(text || '').toLowerCase();
  const bad = ['saya mau tanya','saya ingin tanya','aku mau tanya','saya tertarik','saya mau daftar','saya ingin daftar'];
  return bad.some(p => t.includes(p));
};

const hasSpecificPriceOrContact = (text) => {
  const t = String(text || '');
  return /(rp\s?\d|idr\s?\d|\$\s?\d|\b08\d{8,}\b|\b\d{4,}\b)/i.test(t);
};

const hasContinuationSignal = (text) => continuationSignals.some(re => re.test(String(text || '')));

let kept = [];
let rejected = [];
let warnings = [];
const seenContent = new Set();
const seenStrategy = new Set();
let openerViolationCount = 0;

for (let i = 0; i < sourceTemplates.length; i++) {
  const t = sourceTemplates[i] || {};
  const item = {
    name: String(t.name || ('Template ' + (i + 1))).trim(),
    strategy_tag: String(t.strategy_tag || '').trim(),
    content: String(t.content || '').trim(),
    category,
    sub_category: intent,
    requires_rag: !!t.requires_rag || /\[RAG:/i.test(String(t.content || ''))
  };

  const hardIssues = [];
  const softIssues = [];
  if (!item.content || item.content.length < 20) hardIssues.push('content_too_short');
  if (item.content.length > 700) hardIssues.push('content_too_long');
  if (looksCustomerPerspective(item.content)) hardIssues.push('customer_perspective');
  if (hasSpecificPriceOrContact(item.content)) hardIssues.push('specific_number_or_contact');

  const invalidPlaceholders = extractPlaceholders(item.content).filter(p => !allowedPlaceholders.has(p));
  if (invalidPlaceholders.length) hardIssues.push('invalid_placeholder:' + invalidPlaceholders.join(','));

  if (replyMode === 'continuation') {
    const openerViolation = openerRegex.test(item.content) || openingPhrases.some(re => re.test(item.content));
    if (openerViolation) {
      hardIssues.push('opener_violation');
      openerViolationCount++;
    }
    if (!hasContinuationSignal(item.content)) softIssues.push('weak_continuation_signal');
  } else if (replyMode === 'mixed') {
    if (openerRegex.test(item.content) && !hasContinuationSignal(item.content)) softIssues.push('opening_style_in_mixed');
  } else if (replyMode === 'opening') {
    if (!openerRegex.test(item.content)) softIssues.push('missing_opening_tone');
  }

  const norm = normalizeText(item.content);
  if (!norm) hardIssues.push('empty_after_normalize');
  if (seenContent.has(norm)) hardIssues.push('duplicate_content');

  const strategyKey = item.strategy_tag.toLowerCase();
  if (strategyKey && seenStrategy.has(strategyKey)) hardIssues.push('duplicate_strategy_tag');
  if (strategyPool.length && strategyKey && !strategyPool.includes(strategyKey)) softIssues.push('strategy_tag_outside_pool');

  if (hardIssues.length) {
    rejected.push({ index: i, name: item.name, strategy_tag: item.strategy_tag, issues: hardIssues.concat(softIssues), preview: item.content.slice(0, 180) });
    continue;
  }

  seenContent.add(norm);
  if (strategyKey) seenStrategy.add(strategyKey);
  if (softIssues.length) warnings.push({ index: i, name: item.name, soft_issues: softIssues });
  kept.push(item);
}

const finalTemplates = kept.slice(0, targetCount);
const shortage = Math.max(0, targetCount - finalTemplates.length);
const warningCount = warnings.length;
const needsManualReview = !input.parse_ok || shortage > 0 || rejected.length > 0 || warningCount > 0;
let score = 100;
if (!input.parse_ok) score -= 40;
score -= shortage * 12;
score -= Math.min(30, rejected.length * 2);
score -= Math.min(15, warningCount);
score = Math.max(0, score);

const issues = [];
if (!input.parse_ok) issues.push('parse_error:' + (input.parse_error || 'unknown'));
if (shortage > 0) issues.push('shortage:' + shortage);
if (rejected.length > 0) issues.push('rejected:' + rejected.length);
if (warningCount > 0) issues.push('warnings:' + warningCount);
if (openerViolationCount > 0) issues.push('opener_violation:' + openerViolationCount);

return [{
  json: {
    intent,
    category,
    label,
    reply_mode: replyMode,
    greeting_policy: greetingPolicy,
    taxonomy_source: taxonomySource,
    targetCount,
    generationCount: input.generationCount || sourceTemplates.length,
    parsed_count: input.parsed_count || sourceTemplates.length,
    parse_ok: !!input.parse_ok,
    parse_error: input.parse_error || null,
    final_count: finalTemplates.length,
    rejected_count: rejected.length,
    warning_count: warningCount,
    opener_violation_count: openerViolationCount,
    shortage,
    quality_score: score,
    needs_manual_review: needsManualReview,
    issues,
    rejected,
    warnings,
    templates: finalTemplates
  }
}];

const items = $input.all();
const form = $('Input Gaya Bahasa').first().json;
const gaya = form['Gaya Bahasa'];
const botId = form['Bot ID'] || null;
const intentFilter = String(form['Intent Key Filter (opsional)'] || '').trim();

let allTemplates = [];
let report = [];
let totalRejected = 0;
let totalWarnings = 0;
let totalOpenerViolations = 0;
let intentsNeedingReview = 0;
let taxonomySourceCounts = {};

for (const item of items) {
  const row = item.json || {};
  const tpls = Array.isArray(row.templates) ? row.templates : [];
  allTemplates.push(...tpls);
  totalRejected += row.rejected_count || 0;
  totalWarnings += row.warning_count || 0;
  totalOpenerViolations += row.opener_violation_count || 0;
  if (row.needs_manual_review) intentsNeedingReview++;
  const taxonomySource = row.taxonomy_source || 'db';
  taxonomySourceCounts[taxonomySource] = (taxonomySourceCounts[taxonomySource] || 0) + 1;
  report.push({
    intent: row.intent,
    label: row.label || row.intent,
    category: row.category,
    reply_mode: row.reply_mode || 'continuation',
    greeting_policy: row.greeting_policy || 'forbidden',
    taxonomy_source: taxonomySource,
    target: row.targetCount,
    generated: row.generationCount,
    parsed: row.parsed_count,
    final: row.final_count,
    shortage: row.shortage,
    rejected: row.rejected_count,
    warnings: row.warning_count || 0,
    opener_violations: row.opener_violation_count || 0,
    parse_ok: row.parse_ok,
    quality_score: row.quality_score,
    needs_manual_review: row.needs_manual_review,
    issues: row.issues || []
  });
}

report.sort((a, b) => String(a.intent).localeCompare(String(b.intent)));
allTemplates.sort((a, b) => String(a.sub_category || '').localeCompare(String(b.sub_category || '')) || String(a.name || '').localeCompare(String(b.name || '')));

const avgQuality = report.length ? Math.round(report.reduce((sum, r) => sum + (r.quality_score || 0), 0) / report.length) : 0;

const output = {
  meta: {
    generator: 'Template Generator V4.2.1 — Taxonomy-Driven (Review JSON + RTF)',
    mode: 'taxonomy-driven',
    gaya_bahasa: gaya,
    bot_id: botId,
    intent_filter: intentFilter || null,
    taxonomy_source_counts: taxonomySourceCounts,
    total_templates: allTemplates.length,
    total_intents: report.length,
    intents_needing_manual_review: intentsNeedingReview,
    total_rejected_drafts: totalRejected,
    total_warnings: totalWarnings,
    total_opener_violations: totalOpenerViolations,
    average_quality_score: avgQuality,
    generated_at: new Date().toISOString()
  },
  quality_report: report,
  templates: allTemplates
};

const dateStr = new Date().toISOString().slice(0, 10);
const jsonFileName = 'templates_review_ready_taxonomy_' + dateStr + '.json';
const rtfFileName = 'templates_review_taxonomy_' + dateStr + '.rtf';

const rtfEscape = (value) => String(value ?? '')
  .replace(/\\/g, '\\\\')
  .replace(/\{/g, '\\{')
  .replace(/\}/g, '\\}')
  .replace(/\r\n/g, '\n')
  .replace(/\r/g, '\n')
  .replace(/\n/g, '\\line ');

const rtfLine = (text = '') => rtfEscape(text) + '\\par\n';
const rtfBlank = () => '\\par\n';
const rtfHeading1 = (text) => '{\\b\\fs30 ' + rtfEscape(text) + '}\\par\n';
const rtfHeading2 = (text) => '{\\b\\fs26 ' + rtfEscape(text) + '}\\par\n';
const rtfHeading3 = (text) => '{\\b\\fs22 ' + rtfEscape(text) + '}\\par\n';

let rtf = '{\\rtf1\\ansi\\deff0{\\fonttbl{\\f0 Calibri;}}\\viewkind4\\uc1\\pard\\f0\\fs22\n';
rtf += rtfHeading1('Dokumentasi Template Chatbot (Review V4.2.1 Taxonomy-Driven)');
rtf += rtfBlank();
rtf += rtfLine('Generated: ' + new Date().toLocaleString());
rtf += rtfLine('Gaya Bahasa: ' + gaya);
rtf += rtfLine('Bot ID: ' + (botId || '-'));
rtf += rtfLine('Intent Filter: ' + (intentFilter || '-'));
rtf += rtfLine('Total intent: ' + report.length);
rtf += rtfLine('Total template final: ' + allTemplates.length);
rtf += rtfLine('Rata-rata quality score: ' + avgQuality);
rtf += rtfLine('Total opener violation (draft): ' + totalOpenerViolations);
rtf += rtfLine('Intent perlu review manual: ' + intentsNeedingReview);
rtf += rtfLine('Taxonomy source: ' + Object.entries(taxonomySourceCounts).map(([k, v]) => k + '=' + v).join(', '));
rtf += rtfBlank();

rtf += rtfHeading2('Ringkasan Kualitas per Intent');
rtf += rtfLine('Format: Intent | Mode | Greet Policy | Target | Final | Reject | Warn | Opener | Score | Review');
for (const r of report) {
  rtf += rtfLine([
    r.intent,
    r.reply_mode,
    r.greeting_policy,
    'target=' + r.target,
    'final=' + r.final,
    'reject=' + r.rejected,
    'warn=' + r.warnings,
    'opener=' + r.opener_violations,
    'score=' + r.quality_score,
    'review=' + (r.needs_manual_review ? 'Ya' : 'Tidak')
  ].join(' | '));
  if (Array.isArray(r.issues) && r.issues.length) {
    rtf += rtfLine('  Issues: ' + r.issues.join(', '));
  }
}
rtf += rtfBlank();

const grouped = {};
for (const t of allTemplates) {
  if (!grouped[t.category]) grouped[t.category] = {};
  if (!grouped[t.category][t.sub_category]) grouped[t.category][t.sub_category] = [];
  grouped[t.category][t.sub_category].push(t);
}

rtf += rtfHeading2('Template Final (Siap Direview)');
for (const category of Object.keys(grouped).sort()) {
  rtf += rtfBlank();
  rtf += rtfHeading2('Category: ' + category);
  for (const subCategory of Object.keys(grouped[category]).sort()) {
    rtf += rtfHeading3('Intent: ' + subCategory);
    grouped[category][subCategory].forEach((t, idx) => {
      const meta = [];
      if (t.strategy_tag) meta.push('strategy: ' + t.strategy_tag);
      if (t.requires_rag) meta.push('RAG');
      rtf += rtfLine((idx + 1) + '. ' + (t.name || 'Unnamed') + (meta.length ? ' [' + meta.join(' | ') + ']' : ''));
      rtf += rtfLine(t.content || '');
      rtf += rtfBlank();
    });
  }
}
rtf += '}';

const jsonString = JSON.stringify(output, null, 2);
return [{
  json: {
    fileName: jsonFileName,
    reviewFileName: rtfFileName,
    totalTemplates: allTemplates.length,
    totalIntents: report.length,
    averageQualityScore: avgQuality,
    intentsNeedingReview: intentsNeedingReview,
